    loop i in 0..toon_len(rows) {
        let row: ToonNode = toon_at(rows, i);
        let code: Text = "EMPTY";
        if toon_has_key(row, "meta") {
            let meta: ToonNode = toon_key(row, "meta");
            if toon_has_key(meta, "code") {
                code = toon_get_text_or(meta, "code", "EMPTY");
            }
        }
        fx {
            println("row ", i, " = ", code);
        }
        if code == "EMPTY" {
            missing = missing + 1;
        }
    }

    fx {
        println("missing = ", missing);
    }

    toon_close(doc);
    ret;
}

use "bench_support";

fn main() -> Void {
    if !has_toon() {
        fx { println("yyjson unavailable"); }
        ret;
    }

    let doc: ToonDoc;
    fx { doc = toon_parse_file("support_jobs.json"); }
    let root: ToonNode = toon_root(doc);
    let jobs: ToonNode = toon_key(root, "jobs");
    let ready: Int = 0;
    let review: Int = 0;
    let blocked: Int = 0;

    loop i in 0..toon_len(jobs) {
        let job: ToonNode = toon_at(jobs, i);
        let name: Text = toon_get_text(job, "name");
        let rawScore: Int = toon_get_int_or(job, "score", DefaultScore);
        let score: Int = clampSupport(rawScore);
        let status: Text = classifySupport(score);

        fx {
            println("job ", i, " -> ", name, " / ", status, " / ", score);
        }

        if status == "ready" {
            ready = ready + 1;
        }
        if status == "review" {
            review = review + 1;
        }
        if status == "blocked" {
            blocked = blocked + 1;
        }
    }

    fx {
        println("ready = ", ready);
        println("review = ", review);
        println("blocked = ", blocked);
    }

    toon_close(doc);
    ret;
}

files.bench_support:
mod BenchSupport {
    export const DefaultScore: Int = 50;

    @pure
    export fn classifySupport(score: Int) -> Text {
        if score >= 90 {
            ret "ready";
        }
        if score >= 70 {
            ret "review";
        }
        ret "blocked";
    }

    @pure
    export fn clampSupport(score: Int) -> Int {
        if score > 100 {
            ret 100;
        }
        if score < 0 {
            ret 0;
        }
        ret score;
    }
}
